// ---------------------------------------------------------------------------------------------
// 2. REFINERY BAYS / CYCLE TIME
// ---------------------------------------------------------------------------------------------
// Salts are grouped into 3 physical "bays" of 3 salts each: bay = floor(saltIndex/3) — bay 0
// (Combustion) handles salts 0-2, bay 1 (Synthesis) handles salts 3-5, bay 2 (Polymerize) handles
// salts 6-8. Each bay has its OWN cycle-time timer (confirmed by the `Refinery[0][bay+1]` timer
// slots referenced throughout N.js, e.g. lines 5846, 6575, 11970-11971).
//
// "CycleInitialTime" == d, p._customBlock_Refinery(d,b) where b = BAY index (0,1,2), N.js:12192-12194:
//   DNSM.RefineSpdPCTdn = 0
//   if (b == 2) DNSM.RefineSpdPCTdn = MealBonusesS.PolyRefSpd + ResearchStuff("Grid_Bonus",48,0)  // Polymerize-only
//   return Math.ceil(
//     900 * Math.pow(4, Math.floor(b)) * Math.pow(25, Math.max(0, b-1))
//     / ( (1 + (
//           AlchVials.RefSpd
//         + ( SaltLick(2)                                    // see SALT_LICK_UPGRADES row index 2
//         + ( FamBonusQTYs["24"]
//         + ( Labb("SigilBonus","Blank",10,0)
//         + ( StampBonusOfTypeX("RefinerySpd")
//         + ( Breeding("ShinyBonusS","Nah",15,-1)
//         + ( WorkbenchStuff("ConstMasteryBonus",0,0)
//         + ( ArcadeBonus(25)
//         + ( Summoning("VotingBonusz",33,0)
//           + ResearchStuff("Grid_Bonus",49,0) ) ) ) ) ) ) ) ) ) / 100 )
//     * Math.max(1, MainframeBonus(2))                        // Lab chip "Gilded_Cyclical_Tubing", 3x if active
//     * (1 + Thingies("LegendPTS_bonus",19,0) / 100)           // Legend Talent "More_Soot_More_Salt" (idx 19)
//     * (1 + DNSM.RefineSpdPCTdn / 100)                        // Polymerize-only: meal + research-grid bonus
//   )
// This IS the "Cycle Speed" stat-recipe entry point referenced in the task brief (~14-15 terms
// account-wide: the 9 additive terms above, + Lab-chip multiplier, + Legend-Talent multiplier, +
// (Polymerize-only) meal + research-grid = up to 12-13 distinct bonus SOURCES feeding 3 multiplier
// slots — close enough to the "~14-15 terms" estimate that this is confidently the right hook).
// All bonus-lookup terms are per-account VALUES, out of scope for this gamedata file — only the
// term LIST and formula shape are transcribed here for a later recipe-writing agent.
//
// BASE cycle time per bay (b, before any speed bonus), i.e. `900 * 4^floor(b) * 25^max(0,b-1)`:
export const REFINERY_BAY_BASE_CYCLE_SECONDS = [
  900, // bay 0 "Combustion": 900 * 4^0 * 25^0 = 900s (15 min)
  3600, // bay 1 "Synthesis":  900 * 4^1 * 25^0 = 3600s (1 hr)
  360000, // bay 2 "Polymerize": 900 * 4^2 * 25^1 = 360000s (100 hr / ~4.17 days)
];
// Cross-checked exactly against idleon-toolbox/parsers/world-3/refinery.ts's
// computeRefineryCycleTimes(): combustionTime base 900, synthesisTime base 3600, polymerizeTime
// base 14400*25=360000 — 0 mismatch.

// ---------------------------------------------------------------------------------------------
// 3. POWER CAP / POWER PER CYCLE / COST SCALING — rank-based formulas (apply to ANY salt)
// ---------------------------------------------------------------------------------------------
// "PowerCAP" == d, p._customBlock_Refinery(d,b) where b = RANK, N.js:12191:
//   Math.max(RANDOlist[18][Math.min(b, RANDOlist[18].length - 2)], 25)
// RANDOlist[18] (ka.RANDOlist(), N.js byte offset 13543388) is a 26-entry table; the `-2` clamp
// means index 24 (value 900000) is the effective ceiling for any rank >= 24 — entries 24 and 25
// (both 900000/1000000-ish) are functionally dead weight beyond that clamp, transcribed verbatim
// anyway since that's exactly what's in N.js:
export const REFINERY_POWER_CAP_BY_RANK = [
  50, 50, 200, 800, 3000, 8000, 14000, 20000, 30000, 40000, 50000, 65000, 80000, 100000, 200000,
  300000, 400000, 500000, 600000, 700000, 800000, 900000, 1000000, 1000000, 1000000, 1000000,
];

// "PowerPerCycle" == d, N.js:12192: Math.floor(Math.min(250000, Math.pow(b,1.3) * (1 + Companions(35))))
//   (b = rank; Companions(35) is a per-account companion-set bonus, out of scope — cited for the hook)
// "CapMulti" == d, N.js:12192: Math.ceil(Math.max(RANDOlist[18][min(b,len-2)], 25) / 50)  (b = rank; usage not traced further)
// "RewardPct" == d, N.js:12197: Math.floor(b)  (identity floor, used for display/task-progress scaling)
//
// "CostsMulti" == d, N.js:12191-12192 (b = rank of the salt slot being refined):
//   DummyText2.indexOf("SaltySpitoon") != -1
//     ? ( Tasks[2][2][6] >= Number(DummyText2.replace("SaltySpitoon_","")) ? Math.floor(Math.pow(b,1.3))
//                                                                          : Math.floor(Math.pow(b,1.5)) )
//     : Math.floor(Math.pow(b,1.5))
// i.e. base cost-per-rank scaling is rank^1.5, discounted to rank^1.3 once a Task-Shop upgrade
// tier (Tasks[2][2][6], the "Refinery Salt Task Level") reaches the salt's own index — a per-
// account task-shop progression value, out of scope; cited only as the branch condition.
export const REFINERY_COST_MULTIPLIER_EXPONENT = { normal: 1.5, discounted: 1.3 };

